import type { ElementOf } from './types';
import type { Placement } from '../shared/components/popper/types';

export const PositionEnum = [
  'leftTop',
  'topLeft',
  'leftBottom',
  'bottomLeft',
  'rightTop',
  'topRight',
  'rightBottom',
  'bottomRight',
  /**
   * @deprecated `xxxCenter` deprecated
   */
  'leftCenter',
  'rightCenter',
  'topCenter',
  'bottomCenter',
  'top',
  'bottom',
  'left',
  'right',
] as const;

export type PositionType = ElementOf<typeof PositionEnum>;

export const getFloatingUIPlacement = (placement: PositionType): Placement => {
  switch (placement) {
    case 'top':
    case 'topCenter':
      return 'top';
    case 'right':
    case 'rightCenter':
      return 'right';
    case 'bottom':
    case 'bottomCenter':
      return 'bottom';
    case 'left':
    case 'leftCenter':
      return 'left';
    case 'bottomLeft':
      return 'bottom-start';
    case 'bottomRight':
      return 'bottom-end';
    case 'topLeft':
      return 'top-start';
    case 'topRight':
      return 'top-end';
    case 'leftTop':
      return 'left-start';
    case 'leftBottom':
      return 'left-end';
    case 'rightTop':
      return 'right-start';
    case 'rightBottom':
      return 'right-end';
    default:
      throw new Error(`Placement \`${placement}\` is invalid.`);
  }
};
